    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         action: 'update',
        //         arg: { instType: 'sp', channel: 'candle1D', instId: 'ETHUSDT' },
        //         data: [
        //             [
        //                 '1728316800000',
        //                 '2474.5',
        //                 '2478.21',
        //                 '2459.8',
        //                 '2463.51',
        //                 '86.0551'
        //             ]
        //         ],
        //         ts: 1728317607657
        //     }
        //
        Object arg = this.safeDict(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object market = this.getMarketFromArg(arg);
        Object marketId = Helpers.GetValue(market, "id");
        Object hash = "ohlcv:";
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object channel = this.safeString(arg, "channel");
        Object klineType = Helpers.slice(channel, 6, null);
        Object timeframe = this.findTimeframe(klineType);
        if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(marketId, "_DMCBL"), 0)))
        {
            market = this.handleDMCBLMarketByMessageHashes(market, hash, client, timeframe);
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        if (!Helpers.isTrue((Helpers.inOp(this.ohlcvs, symbol))))
        {
            Helpers.addElementToObject(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}});
        }
        if (!Helpers.isTrue((Helpers.inOp(Helpers.GetValue(this.ohlcvs, symbol), timeframe))))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue()));
        }
        Object stored = Helpers.GetValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object candle = this.safeList(data, i, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object parsed = this.parseWsOHLCV(candle, market);
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        Object messageHash = Helpers.add(Helpers.add(Helpers.add(hash, symbol), ":"), timeframe);
        client.resolve(stored, messageHash);
    }

