    public void handleOrderBook(Client client, Object message)
    {
        //
        //     {
        //         action: 'update',
        //         arg: { instType: 'sp', channel: 'books', instId: 'ETHUSDT' },
        //         data: [
        //             {
        //                 asks: [ [ 2507.07, 0.4248 ] ],
        //                 bids: [ [ 2507.05, 0.1198 ] ],
        //                 checksum: -1400923312,
        //                 ts: '1728339446908'
        //             }
        //         ],
        //         ts: 1728339446908
        //     }
        //
        Object arg = this.safeDict(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object market = this.getMarketFromArg(arg);
        Object marketId = Helpers.GetValue(market, "id");
        Object hash = "books:";
        if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(marketId, "_DMCBL"), 0)))
        {
            market = this.handleDMCBLMarketByMessageHashes(market, hash, client);
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object channel = this.safeString(arg, "channel");
        Object messageHash = Helpers.add(hash, symbol);
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object rawOrderBook = this.safeDict(data, 0);
        Object timestamp = this.safeInteger(rawOrderBook, "ts");
        Object incrementalBook = channel;
        if (Helpers.isTrue(incrementalBook))
        {
            if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
            {
                Object ob = this.countedOrderBook(new java.util.HashMap<String, Object>() {{}});
                Helpers.addElementToObject(ob, "symbol", symbol);
                Helpers.addElementToObject(this.orderbooks, symbol, ob);
            }
            Object storedOrderBook = Helpers.GetValue(this.orderbooks, symbol);
            Object asks = this.safeList(rawOrderBook, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object bids = this.safeList(rawOrderBook, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            this.handleDeltas(Helpers.GetValue(storedOrderBook, "asks"), asks);
            this.handleDeltas(Helpers.GetValue(storedOrderBook, "bids"), bids);
            Helpers.addElementToObject(storedOrderBook, "timestamp", timestamp);
            Helpers.addElementToObject(storedOrderBook, "datetime", this.iso8601(timestamp));
            Object checksum = this.safeBool(this.options, "checksum", true);
            Object isSnapshot = Helpers.isEqual(this.safeString(message, "action"), "snapshot");
            if (Helpers.isTrue(!Helpers.isTrue(isSnapshot) && Helpers.isTrue(checksum)))
            {
                Object storedAsks = Helpers.GetValue(storedOrderBook, "asks");
                Object storedBids = Helpers.GetValue(storedOrderBook, "bids");
                Object asksLength = Helpers.getArrayLength(storedAsks);
                Object bidsLength = Helpers.getArrayLength(storedBids);
                Object payloadArray = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                for (var i = 0; Helpers.isLessThan(i, 25); i++)
                {
                    if (Helpers.isTrue(Helpers.isLessThan(i, bidsLength)))
                    {
                        ((java.util.List<Object>)payloadArray).add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(storedBids, i), 2), 0));
                        ((java.util.List<Object>)payloadArray).add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(storedBids, i), 2), 1));
                    }
                    if (Helpers.isTrue(Helpers.isLessThan(i, asksLength)))
                    {
                        ((java.util.List<Object>)payloadArray).add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(storedAsks, i), 2), 0));
                        ((java.util.List<Object>)payloadArray).add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(storedAsks, i), 2), 1));
                    }
                }
                Object payload = String.join((String)":", (java.util.List<String>)payloadArray);
                Object calculatedChecksum = this.crc32(payload, true);
                Object responseChecksum = this.safeInteger(rawOrderBook, "checksum");
                if (Helpers.isTrue(!Helpers.isEqual(calculatedChecksum, responseChecksum)))
                {
                    this.spawn(() -> { try { this.handleCheckSumError(client, symbol, messageHash); } catch(Exception _e) { throw new RuntimeException(_e); } });
                    return;
                }
            }
        } else
        {
            Object orderbook = this.orderBook(new java.util.HashMap<String, Object>() {{}});
            Object parsedOrderbook = this.parseOrderBook(rawOrderBook, symbol, timestamp);
            Helpers.callDynamically(orderbook, "reset", new Object[]{parsedOrderbook});
            Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
        }
        client.resolve(Helpers.GetValue(this.orderbooks, symbol), messageHash);
    }

    public java.util.concurrent.CompletableFuture<Object> handleCheckSumError(Client client, Object symbol, Object messageHash)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            (this.unWatchOrderBook(symbol)).join();
            var error = new ChecksumError(Helpers.add(Helpers.add(this.id, " "), this.orderbookChecksumMessage(symbol)));
            client.reject(error, messageHash);
            return null;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

