    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         action: 'update',
        //         arg: { instType: 'sp', channel: 'trade', instId: 'ETHUSDT' },
        //         data: [ [ '1728341807469', '2421.41', '0.478', 'sell' ] ],
        //         ts: 1728341807482
        //     }
        //
        Object arg = this.safeDict(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object market = this.getMarketFromArg(arg);
        Object marketId = Helpers.GetValue(market, "id");
        Object hash = "trade:";
        if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(marketId, "_DMCBL"), 0)))
        {
            market = this.handleDMCBLMarketByMessageHashes(market, hash, client);
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        if (!Helpers.isTrue((Helpers.inOp(this.trades, symbol))))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            Helpers.addElementToObject(this.trades, symbol, new ArrayCache(((Number)limit).intValue()));
        }
        Object stored = Helpers.GetValue(this.trades, symbol);
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(!Helpers.isEqual(data, null)))
        {
            data = this.sortBy(data, 0);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object trade = this.safeList(data, i);
                Object parsed = this.parseWsTrade(trade, market);
                Helpers.callDynamically(stored, "append", new Object[]{parsed});
            }
        }
        Object messageHash = Helpers.add(hash, symbol);
        client.resolve(stored, messageHash);
    }

