    public void handleOHLCVUnSubscription(Client client, Object message)
    {
        Object arg = this.safeDict(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object instType = this.safeStringLower(arg, "instType");
        Object type = ((Helpers.isTrue((Helpers.isEqual(instType, "sp"))))) ? "spot" : "swap";
        Object instId = this.safeString(arg, "instId");
        Object channel = this.safeString(arg, "channel");
        Object interval = Helpers.replace((String)channel, (String)"candle", (String)"");
        Object timeframes = this.safeDict(this.options, "timeframesForWs");
        Object timeframe = this.findTimeframe(interval, timeframes);
        Object market = this.safeMarket(instId, null, null, type);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object messageHash = Helpers.add(Helpers.add(Helpers.add("unsubscribe:ohlcv:", timeframe), ":"), Helpers.GetValue(market, "symbol"));
        Object subMessageHash = Helpers.add(Helpers.add(Helpers.add("ohlcv:", symbol), ":"), timeframe);
        if (Helpers.isTrue(Helpers.inOp(this.ohlcvs, symbol)))
        {
            if (Helpers.isTrue(Helpers.inOp(Helpers.GetValue(this.ohlcvs, symbol), timeframe)))
            {
                ((java.util.Map<String,Object>)Helpers.GetValue(this.ohlcvs, symbol)).remove((String)timeframe);
            }
        }
        this.cleanUnsubscription(client, subMessageHash, messageHash);
    }
